  &reftitle.examples;

   Пример использования функции fscanf


<?php

$handle = fopen("users.txt", "r");

while ($userinfo = fscanf($handle, "%s\t%s\t%s\n")) {
    list ($name, $profession, $countrycode) = $userinfo;
    //... совершаем какие-либо действия над значениями
}

fclose($handle);

?>




